// Canonical KJV book metadata for the /connections Web of Scripture feature.
// Per-chapter verse counts are in the runtime cross-references.json (generated by scripts/process-cross-refs.ts).
// This file is used for: VerseSearch autocomplete, tooltip display, BookLabels positioning.

export interface BookInfo {
  index: number
  name: string
  abbr: string          // OSIS abbreviation
  displayAbbr: string   // Short display name
  chapters: number
  verseStart: number    // Cumulative verse index (0-based) at start of book
  verseEnd: number      // Cumulative verse index of last verse (inclusive)
  chapterStart: number  // Cumulative chapter index (0-based) at start of book
  testament: 'OT' | 'NT'
  totalVerses: number
}

export const TOTAL_VERSES = 31102   // KJV total (Gen 1:1 = index 0, Rev 22:21 = index 31101)
export const TOTAL_CHAPTERS = 1189  // KJV total chapters

