// Build a fast lookup map from OSIS abbreviation to book index
export const ABBR_TO_INDEX: Record<string, number> = {}
for (const book of BOOKS) {
  ABBR_TO_INDEX[book.abbr] = book.index
}

// Index of the first NT book (Matthew) — used for OT/NT divider x-position
export const NT_START_BOOK_INDEX = 39

/**
 * Resolve a verse index (0–31101) back to a human-readable reference.
 * Returns { book, chapter, verse } — all 1-based for chapter and verse.
 * Requires the chapters array from the runtime CrossReferenceData.
 */
export function resolveVerseIndex(
  verseIndex: number,
  chapters: { book: number; chapter: number; verseCount: number; verseStart: number }[]
): { book: BookInfo; chapter: number; verse: number } | null {
  if (verseIndex < 0 || verseIndex >= TOTAL_VERSES) return null

  // Binary search on chapters array
  let lo = 0
  let hi = chapters.length - 1
  while (lo < hi) {
    const mid = (lo + hi + 1) >> 1
    if (chapters[mid].verseStart <= verseIndex) {
      lo = mid
    } else {
      hi = mid - 1
    }
  }
  const ch = chapters[lo]
  return {
    book: BOOKS[ch.book],
    chapter: ch.chapter,
    verse: verseIndex - ch.verseStart + 1,
  }
}

/**
 * Format a resolved verse reference as a readable string.
 * e.g. { book: Daniel, chapter: 7, verse: 13 } → "Dan 7:13"
 */
export function formatVerseRef(
  verseIndex: number,
  chapters: { book: number; chapter: number; verseCount: number; verseStart: number }[]
): string {
  const resolved = resolveVerseIndex(verseIndex, chapters)
  if (!resolved) return `[${verseIndex}]`
  return `${resolved.book.displayAbbr} ${resolved.chapter}:${resolved.verse}`
}
